mapper.select:
select course_name from course where teacher_id=#{userId}

    and course_name like concat('%',#{classname},'%')

and status = 1

select ep.title as examName, ec.id as examId
from exam_course ec
inner join course c on ec.class_id = c.id
inner join exam_paper ep on ec.paper_id = ep.id
where ec.teacher_id = #{userId}
and c.course_name = #{courseName}
